    gridTemplateColumns: 'repeat(auto-fit, minmax(130px, 1fr))',
    gap: 10,
    marginBottom: '1.25rem',
  },
  statCard: {
    backgroundColor: '#f6f7f9',
    borderRadius: 8,
    padding: '12px 16px',
  },
  statLabel: {
    margin: '0 0 4px',
    fontSize: 12,
    color: '#888',
  },
  statValue: {
    margin: 0,
    fontSize: 24,
    fontWeight: 600,
  },
  // Tabla wrapper
  tableWrap: {
    border: '1px solid #e8e8e8',
    borderRadius: 10,
    overflow: 'hidden',
    backgroundColor: '#fff',
  },
  filterBar: {
    display: 'flex',
    alignItems: 'center',
    gap: 10,
    padding: '10px 16px',
    borderBottom: '1px solid #e8e8e8',
    backgroundColor: '#fafafa',
