  },
  searchWrap: {
    display: 'flex',
    alignItems: 'center',
    flex: 1,
    minWidth: 180,
    border: '1px solid #e0e0e0',
    borderRadius: 6,
    backgroundColor: '#fff',
    padding: '0 10px',
    gap: 6,
  },
  searchIcon: { fontSize: 13 },
  searchInput: {
    flex: 1,
    border: 'none',
    outline: 'none',
    fontSize: 13,
    padding: '6px 0',
    backgroundColor: 'transparent',
    color: '#1a1a1a',
  },
  select: {
    fontSize: 13,
    padding: '6px 10px',
    border: '1px solid #e0e0e0',
    borderRadius: 6,
    backgroundColor: '#fff',
    color: '#1a1a1a',
    cursor: 'pointer',
  },
  countBadge: {
